1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	export function quote(input: { customer: { yearsWithMHPCO: number; previousContract: boolean }; items: { type: string; cursed?: boolean; enchantment?: number }[] }): number {
16	  if (input.items.length === 0) return PROCESSING_FEE;
17	  const groups = new Map<string, { type: string; cursed?: boolean; enchantment?: number }[]>();
18	  for (const item of input.items) {
19	    if (BASE_PREMIUM_BY_TYPE[item.type] === undefined) {
20	      throw new Error(`Unknown item type: ${item.type}`);
21	    }
22	    const list = groups.get(item.type) ?? [];
23	    list.push(item);
24	    groups.set(item.type, list);
25	  }
26	  let policyBaseUnmodified = 0;
27	  let itemSurcharges = 0;
28	  let firstInsurance = 0;
29	  for (const [type, items] of groups) {
30	    const count = items.length;
31	    if (COMPONENT_TYPES.has(type) && count === 3) {
32	      policyBaseUnmodified += 60;
33	      firstInsurance += 60 * FIRST_INSURANCE_RATE;
34	    } else {
35	      for (const item of items) {
36	        const itemBase = BASE_PREMIUM_BY_TYPE[type];
37	        policyBaseUnmodified += itemBase;
38	        if (item.cursed) {
39	          itemSurcharges += itemBase * 0.5;
40	        }
41	        if ((item.enchantment ?? 0) >= 5) {
42	          itemSurcharges += itemBase * 0.3;
43	        }
44	        firstInsurance += itemBase * FIRST_INSURANCE_RATE;
45	      }
46	    }
47	  }
48	  let loyalty = 0;
49	  if (input.customer.yearsWithMHPCO >= 2) {
50	    loyalty = policyBaseUnmodified * 0.2;
51	  }
52	  let followUp = 0;
53	  if (input.customer.previousContract) {
54	    followUp = policyBaseUnmodified * 0.15;
55	  }
56	  return Math.ceil(policyBaseUnmodified + itemSurcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE);
57	}
58	
59	export const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
60	  sword: 1000,
61	  amulet: 600,
62	  staff: 800,
63	  potion: 400,
64	  rune: 250,
65	  moonstone: 250,
66	};
67	
68	export function policyCap(items: { type: string }[]): number {
69	  let sum = 0;
70	  for (const item of items) {
71	    sum += INSURANCE_VALUE_BY_TYPE[item.type];
72	  }
73	  return 2 * sum;
74	}
75	
76	export function claim(
77	  policy: { remainingCap: number; items: { type: string; enchantment?: number }[] },
78	  incident: { damages: { itemType: string; amount: number }[] }
79	): { payout: number; remainingCap: number } {
80	  const damagesByType: Record<string, number> = {};
81	  for (const damage of incident.damages) {
82	    if (damage.amount < 0) {
83	      throw new Error(`Negative damage amount: ${damage.amount}`);
84	    }
85	    damagesByType[damage.itemType] = (damagesByType[damage.itemType] ?? 0) + 1;
86	  }
87	  const insuredByType: Record<string, number> = {};
88	  for (const item of policy.items) {
89	    insuredByType[item.type] = (insuredByType[item.type] ?? 0) + 1;
90	  }
91	  for (const type of Object.keys(damagesByType)) {
92	    if (damagesByType[type] > (insuredByType[type] ?? 0)) {
93	      throw new Error(`More damages of type ${type} than insured items`);
94	    }
95	  }
96	  let payout = 0;
97	  for (const damage of incident.damages) {
98	    const item = policy.items.find((i) => i.type === damage.itemType);
99	    let amount = damage.amount;
100	    if (item && (item.enchantment ?? 0) >= 8) {
101	      amount = amount * 0.5;
102	    }
103	    payout += Math.max(0, amount - 100);
104	  }
105	  payout = Math.min(payout, policy.remainingCap);
106	  payout = Math.floor(payout);
107	  return { payout, remainingCap: policy.remainingCap - payout };
108	}
